"use client";

import { useState, useEffect } from "react";
import { useParams } from "next/navigation";
import { fetchStockAnalysis } from "@/lib/api";
import type { StockAnalysis } from "@/types";
import LoadingSpinner from "@/components/ui/LoadingSpinner";
import Link from "next/link";
import { ArrowLeft, Sparkles, Star } from "lucide-react";

const sentimentLabels: Record<string, string> = {
  bullish: "긍정적",
  bearish: "부정적",
  neutral: "중립",
};

const sentimentColors: Record<string, string> = {
  bullish: "bg-green-500/20 text-green-300 border-green-500/30",
  bearish: "bg-red-500/20 text-red-300 border-red-500/30",
  neutral: "bg-gray-500/20 text-gray-300 border-gray-500/30",
};

export default function StockAnalysisPage() {
  const { code } = useParams<{ code: string }>();
  const [analysis, setAnalysis] = useState<StockAnalysis | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    setLoading(true);
    setError("");
    fetchStockAnalysis(code)
      .then(setAnalysis)
      .catch((e) => {
        const msg = e?.message || "분석 중 오류가 발생했습니다.";
        if (msg.includes("시간이 초과")) {
          setError("AI 분석에 시간이 걸리고 있습니다. 다시 시도해 주세요.");
        } else if (msg.includes("429") || msg.includes("요청이 많") || msg.includes("RATE_LIMITED")) {
          setError("AI 분석 요청이 많습니다. 30초 후 다시 시도해 주세요.");
        } else {
          setError(msg);
        }
      })
      .finally(() => setLoading(false));
  }, [code]);

  const retry = () => {
    setLoading(true);
    setError("");
    fetchStockAnalysis(code)
      .then(setAnalysis)
      .catch((e) => setError(e?.message || "분석 중 오류가 발생했습니다."))
      .finally(() => setLoading(false));
  };

  return (
    <div className="space-y-6 max-w-2xl mx-auto">
      <Link
        href={`/stock/${code}`}
        className="inline-flex items-center text-gray-400 hover:text-white text-sm transition-colors"
      >
        <ArrowLeft className="w-4 h-4 mr-1" /> 종목으로 돌아가기
      </Link>

      {loading && <LoadingSpinner text="쉬운 말로 정리하고 있어요... (최대 1분)" />}

      {error && !loading && (
        <div className="bg-red-500/10 border border-red-500/30 rounded-xl p-4 text-center space-y-2">
          <p className="text-red-300 text-sm">{error}</p>
          <button
            onClick={retry}
            className="text-skyblue text-sm font-medium hover:underline"
          >
            다시 시도
          </button>
        </div>
      )}

      {analysis && !loading && (
        <>
          {/* 헤더 */}
          <div className="flex items-center gap-3">
            <Sparkles className="w-6 h-6 text-skyblue" />
            <div>
              <h1 className="text-xl font-bold">{analysis.stock_name} AI 분석</h1>
              <p className="text-xs text-gray-400">
                {new Date(analysis.analyzed_at).toLocaleString("ko-KR")} 기준
              </p>
            </div>
            <span
              className={`ml-auto text-sm font-bold px-3 py-1 rounded-full border ${
                sentimentColors[analysis.sentiment] ?? sentimentColors.neutral
              }`}
            >
              {sentimentLabels[analysis.sentiment] ?? "중립"}
            </span>
          </div>

          {/* 항목별 카드 */}
          <div className="space-y-3">
            {analysis.items.map((item, i) => (
              <div
                key={i}
                className="bg-white/5 border border-white/10 rounded-xl p-4 space-y-2"
              >
                <div className="flex items-baseline justify-between gap-2">
                  <span className="text-gray-400 text-sm font-medium">{item.label}</span>
                  <span className="text-white font-bold text-sm text-right">{item.result}</span>
                </div>
                <p className="text-gray-200 text-sm">{item.reason}</p>
                <p className="text-gray-500 text-xs">{item.description}</p>
              </div>
            ))}
          </div>

          {/* 종합 별점 */}
          <div className="bg-skyblue/10 border border-skyblue/30 rounded-xl p-5 text-center space-y-3">
            <h2 className="text-skyblue font-bold text-lg">종합 평가</h2>
            <div className="flex justify-center gap-1">
              {[1, 2, 3, 4, 5].map((n) => (
                <Star
                  key={n}
                  className={`w-7 h-7 ${
                    n <= analysis.overall_score
                      ? "text-amber-400 fill-amber-400"
                      : "text-gray-600"
                  }`}
                />
              ))}
            </div>
            <p className="text-sm text-gray-200">{analysis.overall_comment}</p>
          </div>
        </>
      )}
    </div>
  );
}
